'use client';

import { useState, useEffect } from 'react';

type Tab = 'turnos' | 'sitting' | 'qr' | 'alergenos' | 'viajes' | 'countdown';

const BAR_SHIFTS = [
    { day: 'Lunes 10', turno: 'Tarde', personas: ['María G.', 'Pablo M.'], hora: '18:00 - 23:00' },
    { day: 'Martes 11', turno: 'Tarde', personas: ['Carlos R.', 'Ana T.'], hora: '18:00 - 23:00' },
    { day: 'Miércoles 12', turno: 'Noche', personas: ['Lucía F.', 'Andrés L.'], hora: '21:00 - 02:00' },
    { day: 'Jueves 13', turno: 'Tarde', personas: ['Sara V.', 'Miguel S.'], hora: '18:00 - 23:00' },
    { day: 'Viernes 14', turno: 'Noche', personas: ['Eva M.', 'Luis G.', 'Carmen R.'], hora: '20:00 - 03:00' },
    { day: 'Sábado 15', turno: 'Todo el día', personas: ['Todos los disponibles'], hora: '12:00 - 03:00' },
    { day: 'Domingo 16', turno: 'Mediodía', personas: ['María G.', 'Paco V.'], hora: '12:00 - 17:00' },
];

const SITTING_TABLES = [
    { id: 1, nombre: 'Mesa Presidencial', personas: ['Presidente', 'FM Mayor', 'FM Infantil', 'Secretario', 'Tesorera', 'Invitado 1', 'Invitado 2', 'Invitado 3'], capacidad: 8 },
    { id: 2, nombre: 'Mesa 2 — Familias', personas: ['García x4', 'Martínez x3', 'Vacante'], capacidad: 8 },
    { id: 3, nombre: 'Mesa 3 — Jóvenes', personas: ['Lucía', 'Pablo', 'Sara', 'Miguel', 'Eva', 'Luis'], capacidad: 8 },
    { id: 4, nombre: 'Mesa 4 — Infantil', personas: ['Niño 1', 'Niño 2', 'Niño 3', 'Niño 4', 'Niño 5', 'Niño 6'], capacidad: 8 },
];

const ALLERGENS = [
    { fallero: 'María García', alergias: ['Gluten', 'Lactosa'], gravedad: 'Alta', notas: 'Lleva EpiPen' },
    { fallero: 'Pablo Martínez', alergias: ['Frutos secos'], gravedad: 'Media', notas: 'Solo cacahuetes' },
    { fallero: 'Lucía Fernández', alergias: ['Marisco'], gravedad: 'Alta', notas: 'Anafilaxia' },
    { fallero: 'Carlos Ruiz', alergias: ['Huevo'], gravedad: 'Baja', notas: 'Solo crudo' },
    { fallero: 'Eva Moreno', alergias: ['Soja', 'Gluten'], gravedad: 'Media', notas: 'Celiaca diagnosticada' },
];

const TRIPS = [
    {
        nombre: 'Excursión Benidorm',
        fecha: '15-16 Marzo',
        plazas: 52,
        ocupadas: 48,
        autobus: [
            { asiento: '1A', persona: 'María G.' }, { asiento: '1B', persona: 'Pablo M.' },
            { asiento: '2A', persona: 'Carlos R.' }, { asiento: '2B', persona: 'Lucía F.' },
        ],
        hotel: 'Hotel Gran Delfín ★★★★',
        habitaciones: 26,
    },
];

function getCountdown() {
    const now = new Date();
    const year = now.getFullYear();
    let planta = new Date(year, 2, 15, 0, 0, 0);
    if (now > planta) planta = new Date(year + 1, 2, 15, 0, 0, 0);
    const diff = planta.getTime() - now.getTime();
    return {
        days: Math.floor(diff / (1000 * 60 * 60 * 24)),
        hours: Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        minutes: Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60)),
        seconds: Math.floor((diff % (1000 * 60)) / 1000),
    };
}

export default function LogisticsPage() {
    const [activeTab, setActiveTab] = useState<Tab>('turnos');
    const [countdown, setCountdown] = useState(getCountdown());

    useEffect(() => {
        const timer = setInterval(() => setCountdown(getCountdown()), 1000);
        return () => clearInterval(timer);
    }, []);

    const tabs: { key: Tab; label: string; icon: string }[] = [
        { key: 'turnos', label: 'Turnos Barra', icon: '🍺' },
        { key: 'sitting', label: 'Sitting', icon: '🪑' },
        { key: 'qr', label: 'Check-in QR', icon: '📲' },
        { key: 'alergenos', label: 'Alérgenos', icon: '⚕️' },
        { key: 'viajes', label: 'Viajes', icon: '🚌' },
        { key: 'countdown', label: 'Cuenta Atrás', icon: '⏱️' },
    ];

    return (
        <div>
            <div className="page-header">
                <h1 className="page-title">📅 Logística</h1>
                <p className="page-subtitle">Organización de eventos, turnos y servicios</p>
            </div>

            <div className="tabs">
                {tabs.map((t) => (
                    <button key={t.key} className={`tab ${activeTab === t.key ? 'active' : ''}`} onClick={() => setActiveTab(t.key)}>
                        {t.icon} {t.label}
                    </button>
                ))}
            </div>

            {/* TURNOS BARRA */}
            {activeTab === 'turnos' && (
                <div className="animate-fade-in">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                        <h3 className="section-title" style={{ margin: 0 }}>🍺 Cuadrante de Turnos — Semana Fallera</h3>
                        <button className="btn btn-primary">+ Asignar Turno</button>
                    </div>
                    <div className="card">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Día</th>
                                    <th>Turno</th>
                                    <th>Horario</th>
                                    <th>Personas</th>
                                </tr>
                            </thead>
                            <tbody>
                                {BAR_SHIFTS.map((s, i) => (
                                    <tr key={i}>
                                        <td style={{ fontWeight: 600 }}>{s.day}</td>
                                        <td><span className={`badge ${s.turno === 'Noche' ? 'purple' : s.turno === 'Todo el día' ? 'warning' : 'info'}`}>{s.turno}</span></td>
                                        <td>{s.hora}</td>
                                        <td>{s.personas.join(', ')}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* SITTING */}
            {activeTab === 'sitting' && (
                <div className="animate-fade-in">
                    <h3 className="section-title">🪑 Organización de Mesas — Cena Fallera</h3>
                    <div className="grid-2">
                        {SITTING_TABLES.map((table) => (
                            <div key={table.id} className="card-glass">
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
                                    <h4>{table.nombre}</h4>
                                    <span className="badge info">{table.personas.length}/{table.capacidad}</span>
                                </div>
                                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                                    {table.personas.map((p, i) => (
                                        <span key={i} className="hub-feature-tag" style={{
                                            cursor: 'grab',
                                            background: p === 'Vacante' ? 'rgba(239,68,68,0.1)' : undefined,
                                            borderColor: p === 'Vacante' ? 'rgba(239,68,68,0.3)' : undefined,
                                            color: p === 'Vacante' ? 'var(--accent-red)' : undefined,
                                        }}>
                                            {p}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* QR */}
            {activeTab === 'qr' && (
                <div className="animate-fade-in">
                    <div className="grid-2">
                        <div className="card qr-card">
                            <div className="qr-code">📱</div>
                            <h3 style={{ marginBottom: 8 }}>Carnet Digital Fallero</h3>
                            <p style={{ color: 'var(--text-secondary)', fontSize: 14, marginBottom: 16 }}>
                                Escanea este código para registrar tu asistencia
                            </p>
                            <div className="badge success" style={{ fontSize: 14, padding: '8px 16px' }}>✓ Acceso Autorizado</div>
                        </div>
                        <div className="card">
                            <h3 style={{ marginBottom: 20 }}>📊 Registro de Asistencia — Hoy</h3>
                            <div className="stats-grid" style={{ gridTemplateColumns: '1fr 1fr', marginBottom: 20 }}>
                                <div className="stat-card">
                                    <div className="stat-value" style={{ fontSize: 24 }}>87</div>
                                    <div className="stat-label">Check-ins hoy</div>
                                </div>
                                <div className="stat-card">
                                    <div className="stat-value" style={{ fontSize: 24 }}>35%</div>
                                    <div className="stat-label">Asistencia</div>
                                </div>
                            </div>
                            <div>
                                <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 8 }}>Últimos check-ins:</div>
                                {['María G. — 19:32', 'Pablo M. — 19:28', 'Lucía F. — 19:15', 'Carlos R. — 18:50'].map((c, i) => (
                                    <div key={i} style={{ padding: '8px 0', borderBottom: '1px solid var(--border-subtle)', fontSize: 13, display: 'flex', alignItems: 'center', gap: 8 }}>
                                        <span className="badge success" style={{ fontSize: 10 }}>✓</span> {c}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* ALÉRGENOS */}
            {activeTab === 'alergenos' && (
                <div className="animate-fade-in">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                        <h3 className="section-title" style={{ margin: 0 }}>⚕️ Control de Alérgenos</h3>
                        <button className="btn btn-primary">+ Añadir Ficha</button>
                    </div>
                    <div className="card">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Fallero/a</th>
                                    <th>Alergias</th>
                                    <th>Gravedad</th>
                                    <th>Notas</th>
                                </tr>
                            </thead>
                            <tbody>
                                {ALLERGENS.map((a, i) => (
                                    <tr key={i}>
                                        <td style={{ fontWeight: 500 }}>{a.fallero}</td>
                                        <td>
                                            <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                                                {a.alergias.map((al) => (
                                                    <span key={al} className="badge danger">{al}</span>
                                                ))}
                                            </div>
                                        </td>
                                        <td>
                                            <span className={`badge ${a.gravedad === 'Alta' ? 'danger' : a.gravedad === 'Media' ? 'warning' : 'info'}`}>
                                                {a.gravedad}
                                            </span>
                                        </td>
                                        <td style={{ fontSize: 13, color: 'var(--text-secondary)' }}>{a.notas}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* VIAJES */}
            {activeTab === 'viajes' && (
                <div className="animate-fade-in">
                    {TRIPS.map((trip, i) => (
                        <div key={i}>
                            <div className="card" style={{ marginBottom: 20 }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
                                    <div>
                                        <h3 style={{ fontSize: 18 }}>🚌 {trip.nombre}</h3>
                                        <div style={{ color: 'var(--text-secondary)', fontSize: 13 }}>{trip.fecha} • {trip.hotel}</div>
                                    </div>
                                    <span className="badge success">{trip.ocupadas}/{trip.plazas} plazas</span>
                                </div>
                                <div className="progress-bar" style={{ marginBottom: 8 }}>
                                    <div className="progress-fill" style={{ width: `${(trip.ocupadas / trip.plazas) * 100}%` }} />
                                </div>
                                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{trip.plazas - trip.ocupadas} plazas disponibles</div>
                            </div>
                            <div className="grid-2">
                                <div className="card">
                                    <h4 style={{ marginBottom: 12 }}>🚌 Asientos Autobús</h4>
                                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 6 }}>
                                        {trip.autobus.map((a) => (
                                            <div key={a.asiento} style={{
                                                padding: '8px',
                                                background: 'rgba(249,115,22,0.1)',
                                                border: '1px solid rgba(249,115,22,0.2)',
                                                borderRadius: 'var(--radius-sm)',
                                                textAlign: 'center',
                                                fontSize: 11,
                                            }}>
                                                <div style={{ fontWeight: 600 }}>{a.asiento}</div>
                                                <div style={{ color: 'var(--text-secondary)' }}>{a.persona}</div>
                                            </div>
                                        ))}
                                        {Array.from({ length: 8 }, (_, j) => (
                                            <div key={`empty-${j}`} style={{
                                                padding: '8px',
                                                background: 'var(--bg-glass)',
                                                border: '1px dashed var(--border-subtle)',
                                                borderRadius: 'var(--radius-sm)',
                                                textAlign: 'center',
                                                fontSize: 11,
                                                color: 'var(--text-muted)',
                                            }}>
                                                Libre
                                            </div>
                                        ))}
                                    </div>
                                </div>
                                <div className="card">
                                    <h4 style={{ marginBottom: 12 }}>🏨 Habitaciones Hotel</h4>
                                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 8 }}>
                                        {Array.from({ length: 6 }, (_, j) => (
                                            <div key={j} className="feature-item" style={{ padding: 12 }}>
                                                <div style={{ fontWeight: 600, fontSize: 13 }}>Hab. {101 + j}</div>
                                                <div style={{ fontSize: 12, color: j < 4 ? 'var(--accent-green)' : 'var(--text-muted)' }}>
                                                    {j < 4 ? '✓ Asignada' : '— Libre'}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* COUNTDOWN */}
            {activeTab === 'countdown' && (
                <div className="animate-fade-in" style={{ maxWidth: 600, margin: '0 auto' }}>
                    <div className="countdown-card">
                        <div style={{ fontSize: 64, marginBottom: 16 }}>🔥</div>
                        <div className="countdown-title" style={{ fontSize: 22 }}>CUENTA ATRÁS PARA LA PLANTÀ</div>
                        <div className="countdown-timer" style={{ margin: '32px 0' }}>
                            <div className="countdown-unit">
                                <div className="countdown-value" style={{ fontSize: 56 }}>{countdown.days}</div>
                                <div className="countdown-label">Días</div>
                            </div>
                            <div className="countdown-unit">
                                <div className="countdown-value" style={{ fontSize: 56 }}>{countdown.hours}</div>
                                <div className="countdown-label">Horas</div>
                            </div>
                            <div className="countdown-unit">
                                <div className="countdown-value" style={{ fontSize: 56 }}>{countdown.minutes}</div>
                                <div className="countdown-label">Min</div>
                            </div>
                            <div className="countdown-unit">
                                <div className="countdown-value" style={{ fontSize: 56 }}>{countdown.seconds}</div>
                                <div className="countdown-label">Seg</div>
                            </div>
                        </div>
                        <div style={{ fontSize: 14, color: 'var(--text-secondary)' }}>
                            15 de Marzo — ¡Cada segundo cuenta! 🎆
                        </div>
                    </div>
                    <div className="stats-grid" style={{ marginTop: 24, gridTemplateColumns: '1fr 1fr' }}>
                        <div className="stat-card">
                            <div className="stat-icon orange">🌡️</div>
                            <div className="stat-value" style={{ fontSize: 24 }}>16°C</div>
                            <div className="stat-label">Previsión Valencia</div>
                        </div>
                        <div className="stat-card">
                            <div className="stat-icon blue">🌤️</div>
                            <div className="stat-value" style={{ fontSize: 24 }}>Sol</div>
                            <div className="stat-label">Tiempo previsto</div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
